import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import "./Login.css"; // Reuse Login.css for consistent styling

export default function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    password: "",
    role: "student",
    rollNumber: "",
    secretKey: ""
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleRegister = (e) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem("users")) || [];

    // Secret Key validation
    if (
      (formData.role === "admin" && formData.secretKey !== "admin123") ||
      (formData.role === "hr" && formData.secretKey !== "hr123")
    ) {
      alert("❌ Invalid Secret Key for the selected role");
      return;
    }

    // Email already exists
    const userExists = users.find((user) => user.email === formData.email);
    if (userExists) {
      alert("❌ Email already registered");
      return;
    }

    const newUser = {
      name: formData.name,
      email: formData.email,
      password: formData.password,
      role: formData.role,
      rollNumber: formData.role === "student" ? formData.rollNumber : ""
    };

    users.push(newUser);
    localStorage.setItem("users", JSON.stringify(users));
    localStorage.setItem("currentUser", JSON.stringify(newUser));
    navigate("/dashboard");
  };

  return (
    <div className="auth-container">
      <div className="form-box">
        <h2>Register</h2>
        <form onSubmit={handleRegister}>
          <div className="input-group">
            <label>Name</label>
            <input type="text" name="name" required onChange={handleChange} />
          </div>
          <div className="input-group">
            <label>Email</label>
            <input type="email" name="email" required onChange={handleChange} />
          </div>
          <div className="input-group">
            <label>Password</label>
            <input type="password" name="password" required onChange={handleChange} />
          </div>
          <div className="input-group">
            <label>Role</label>
            <select name="role" value={formData.role} onChange={handleChange}>
              <option value="student">Student</option>
              <option value="hr">HR</option>
              <option value="admin">Admin</option>
            </select>
          </div>

          {formData.role === "student" && (
            <div className="input-group">
              <label>Roll Number</label>
              <input type="text" name="rollNumber" required onChange={handleChange} />
            </div>
          )}

          {(formData.role === "admin" || formData.role === "hr") && (
            <div className="input-group">
              <label>Secret Key</label>
              <input type="password" name="secretKey" required onChange={handleChange} />
            </div>
          )}

          <button type="submit" className="auth-button">Register</button>

          <p className="auth-link">
            Already have an account? <Link to="/login">Login here</Link>
          </p>
        </form>
      </div>
    </div>
  );
}
